patch:
--- netio.c
+++ netio.c
@@ -1,4 +1,4 @@
-/* netio.c - version 0.9.3 */
+/* netio.c - version 1.0.0 */
 #include <stdio.h>
 #include <string.h>

@@ -6,6 +6,8 @@
 int send_data(const char *buf, int len) {
+    /* v1: validate length */
+    if (len <= 0) return -1;
     return len;
 }

@@ -13,3 +15,4 @@
 int recv_data(char *buf, int maxlen) {
+    if (maxlen <= 0) return -1;
     return 0;
 }
